import React, { useEffect, useState } from 'react';
import { supabase } from '../supabaseClient';

const TrendingTicker = () => {
  const [items, setItems] = useState([]);

  useEffect(() => {
    const fetchItems = async () => {
      const { data } = await supabase.from('proposals').select('title').limit(10);
      if (data) {
        setItems(data.map(p => p.title));
      } else {
        setItems([
          "Réforme du mandat présidentiel",
          "Nouvelle constitution inclusive",
          "Décentralisation du pouvoir",
          "Justice pour tous",
          "Élections transparentes"
        ]);
      }
    };
    fetchItems();
  }, []);

  const tickerContent = [...items, ...items, ...items];

  return (
    <div className="ticker">
      <div className="ticker-label">À LA UNE</div>
      <div className="ticker-track">
        <div className="ticker-content">
          {tickerContent.map((item, i) => (
            <span key={i} className="ticker-item">📢 {item}</span>
          ))}
        </div>
      </div>
    </div>
  );
};

export default TrendingTicker;
